import React from 'react';
import { Input } from '../../ui';
import {
  JOB_SCHEDULE_TIMEZONES,
  WEEKDAY_OPTIONS,
  defaultRecurrence,
  formatTimeInput,
  parseTimeInput,
  type PlatformJobScheduleRecurrence,
  type ScheduleRecurrenceKind,
} from './scheduleRecurrenceUtils';

type Props = {
  recurrence: PlatformJobScheduleRecurrence;
  scheduleTimezoneId: string;
  onRecurrenceChange: (next: PlatformJobScheduleRecurrence) => void;
  onTimezoneChange: (tz: string) => void;
};

const KIND_OPTIONS: { value: ScheduleRecurrenceKind; label: string }[] = [
  { value: 'none', label: 'Không lặp (chỉ startup / chạy tay)' },
  { value: 'daily', label: 'Hàng ngày' },
  { value: 'weekly', label: 'Hàng tuần' },
  { value: 'monthly', label: 'Hàng tháng' },
  { value: 'yearly', label: 'Hàng năm' },
];

const fieldStyle: React.CSSProperties = { marginBottom: 12 };

export const JobScheduleRecurrenceForm: React.FC<Props> = ({
  recurrence,
  scheduleTimezoneId,
  onRecurrenceChange,
  onTimezoneChange,
}) => {
  const r = recurrence ?? defaultRecurrence();

  const patch = (partial: Partial<PlatformJobScheduleRecurrence>) =>
    onRecurrenceChange({ ...r, ...partial });

  return (
    <div data-testid="job-schedule-recurrence-form">
      <p style={{ fontSize: 13, color: '#64748b', marginTop: 0 }}>
        Giờ chạy theo timezone bên dưới — server lưu UTC và tự tính lịch (kể cả ngày cuối tháng).
      </p>

      <div style={fieldStyle}>
        <label htmlFor="job-schedule-tz" style={{ display: 'block', fontSize: 13, marginBottom: 4 }}>
          Timezone (khóa sổ / cuối kỳ)
        </label>
        <select
          id="job-schedule-tz"
          value={scheduleTimezoneId}
          onChange={(e) => onTimezoneChange(e.target.value)}
          style={{ width: '100%', padding: '8px 10px', borderRadius: 6, border: '1px solid #cbd5e1' }}
          data-testid="job-schedule-timezone"
        >
          {JOB_SCHEDULE_TIMEZONES.map((tz) => (
            <option key={tz.id} value={tz.id}>
              {tz.label}
            </option>
          ))}
        </select>
      </div>

      <div style={fieldStyle}>
        <label htmlFor="job-schedule-kind" style={{ display: 'block', fontSize: 13, marginBottom: 4 }}>
          Lịch lặp
        </label>
        <select
          id="job-schedule-kind"
          value={r.kind}
          onChange={(e) =>
            patch({
              kind: e.target.value as ScheduleRecurrenceKind,
              ...(e.target.value === 'weekly' && !r.daysOfWeek?.length
                ? { daysOfWeek: [1] }
                : {}),
              ...(e.target.value === 'monthly' && !r.dayOfMonth && !r.lastDayOfMonth
                ? { dayOfMonth: 1 }
                : {}),
              ...(e.target.value === 'yearly' && !r.month ? { month: 1, dayOfMonth: 1 } : {}),
            })
          }
          style={{ width: '100%', padding: '8px 10px', borderRadius: 6, border: '1px solid #cbd5e1' }}
        >
          {KIND_OPTIONS.map((o) => (
            <option key={o.value} value={o.value}>
              {o.label}
            </option>
          ))}
        </select>
      </div>

      {r.kind !== 'none' ? (
        <div style={fieldStyle}>
          <label htmlFor="job-schedule-time" style={{ display: 'block', fontSize: 13, marginBottom: 4 }}>
            Giờ chạy (local)
          </label>
          <input
            id="job-schedule-time"
            type="time"
            value={formatTimeInput(r.hour, r.minute)}
            onChange={(e) => {
              const { hour, minute } = parseTimeInput(e.target.value);
              patch({ hour, minute });
            }}
            style={{ width: '100%', padding: '8px 10px', borderRadius: 6, border: '1px solid #cbd5e1' }}
            data-testid="job-schedule-local-time"
          />
        </div>
      ) : null}

      {r.kind === 'weekly' ? (
        <div style={fieldStyle}>
          <span style={{ display: 'block', fontSize: 13, marginBottom: 6 }}>Ngày trong tuần</span>
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
            {WEEKDAY_OPTIONS.map((d) => {
              const checked = (r.daysOfWeek ?? []).includes(d.value);
              return (
                <label key={d.value} style={{ display: 'flex', gap: 4, alignItems: 'center', fontSize: 13 }}>
                  <input
                    type="checkbox"
                    checked={checked}
                    onChange={(e) => {
                      const set = new Set(r.daysOfWeek ?? []);
                      if (e.target.checked) set.add(d.value);
                      else set.delete(d.value);
                      patch({ daysOfWeek: [...set].sort((a, b) => a - b) });
                    }}
                  />
                  {d.label}
                </label>
              );
            })}
          </div>
        </div>
      ) : null}

      {r.kind === 'monthly' ? (
        <div style={fieldStyle}>
          <label style={{ display: 'flex', gap: 8, alignItems: 'center', marginBottom: 8, fontSize: 13 }}>
            <input
              type="checkbox"
              checked={Boolean(r.lastDayOfMonth)}
              onChange={(e) =>
                patch({
                  lastDayOfMonth: e.target.checked,
                  ...(e.target.checked ? { dayOfMonth: undefined } : { dayOfMonth: r.dayOfMonth ?? 1 }),
                })
              }
            />
            Ngày cuối tháng (tự tính theo từng tháng)
          </label>
          {!r.lastDayOfMonth ? (
            <Input
              label="Ngày trong tháng (1–31)"
              type="number"
              value={String(r.dayOfMonth ?? 1)}
              onChange={(e) => patch({ dayOfMonth: Math.min(31, Math.max(1, Number(e.target.value) || 1)) })}
            />
          ) : null}
        </div>
      ) : null}

      {r.kind === 'yearly' ? (
        <div style={fieldStyle}>
          <Input
            label="Tháng (1–12)"
            type="number"
            value={String(r.month ?? 1)}
            onChange={(e) => patch({ month: Math.min(12, Math.max(1, Number(e.target.value) || 1)) })}
          />
          <label style={{ display: 'flex', gap: 8, alignItems: 'center', marginBottom: 8, fontSize: 13 }}>
            <input
              type="checkbox"
              checked={Boolean(r.lastDayOfMonth)}
              onChange={(e) =>
                patch({
                  lastDayOfMonth: e.target.checked,
                  ...(e.target.checked ? { dayOfMonth: undefined } : { dayOfMonth: r.dayOfMonth ?? 1 }),
                })
              }
            />
            Ngày cuối tháng
          </label>
          {!r.lastDayOfMonth ? (
            <Input
              label="Ngày trong tháng (1–31)"
              type="number"
              value={String(r.dayOfMonth ?? 1)}
              onChange={(e) => patch({ dayOfMonth: Math.min(31, Math.max(1, Number(e.target.value) || 1)) })}
            />
          ) : null}
        </div>
      ) : null}
    </div>
  );
};

export default JobScheduleRecurrenceForm;
