import React from 'react';
import { Select } from '../../../ui';
import type { PlatformJobEventType } from '../../../services/jobs';

interface JobEventTypeFilterProps {
  eventTypes: PlatformJobEventType[];
  eventType: string;
  onEventTypeChange: (value: string) => void;
  status: string;
  onStatusChange: (value: string) => void;
}

const STATUS_OPTIONS = [
  { value: '', label: 'Tất cả trạng thái' },
  { value: 'Pending', label: 'Pending' },
  { value: 'Processing', label: 'Processing' },
  { value: 'Completed', label: 'Completed (Pass)' },
  { value: 'Failed', label: 'Failed' },
  { value: 'DeadLetter', label: 'DeadLetter' },
];

export const JobEventTypeFilter: React.FC<JobEventTypeFilterProps> = ({
  eventTypes,
  eventType,
  onEventTypeChange,
  status,
  onStatusChange,
}) => (
  <div style={{ display: 'flex', flexWrap: 'wrap', gap: 12, marginBottom: 16 }}>
    <div style={{ minWidth: 280 }}>
      <Select
        label="Loại event"
        value={eventType}
        onChange={(e) => onEventTypeChange(e.target.value)}
        options={[
          { value: '', label: 'Tất cả loại event' },
          ...eventTypes.map((t) => ({
            value: t.eventType,
            label: `${t.displayName} (${t.eventType})`,
          })),
        ]}
      />
    </div>
    <div style={{ minWidth: 200 }}>
      <Select
        label="Trạng thái"
        value={status}
        onChange={(e) => onStatusChange(e.target.value)}
        options={STATUS_OPTIONS}
      />
    </div>
  </div>
);
