import { adminService } from '../services/admin';
import type { BffAccountDetailDto, BffFeaturePackageDto } from '../services/admin/responseModel';
import {
  buildCompanyScopeJson,
  mergeAllowedCompanyIdsFromPackages,
  parseCompanyScopeJson,
  userScopePackageCode,
  USER_SCOPE_PACKAGE_PREFIX,
} from './companyScopeJson';

/**
 * Sync per-user SCOPE-* package so JWT allowed_company_ids includes selected tenants.
 */
export async function syncAccountCompanyScope(
  account: BffAccountDetailDto,
  selectedCompanyIds: string[],
  allPackages: BffFeaturePackageDto[],
): Promise<void> {
  const homeId = account.companyId ?? '';
  const uniqueIds = [...new Set(selectedCompanyIds.filter(Boolean))];
  if (homeId && !uniqueIds.includes(homeId)) uniqueIds.unshift(homeId);

  const scopeCode = userScopePackageCode(account.username);
  const existingScopePkg = allPackages.find((p) => p.code === scopeCode);
  const userScopeAssignment = account.packages.find((a) =>
    allPackages.some((p) => p.id === a.packageId && p.code.startsWith(USER_SCOPE_PACKAGE_PREFIX)),
  );

  if (uniqueIds.length <= 1) {
    if (userScopeAssignment) {
      await adminService.removePackage(account.id, userScopeAssignment.assignmentId);
    }
    return;
  }

  const scopeJson = buildCompanyScopeJson('listed', uniqueIds);
  let scopePkgId = existingScopePkg?.id;

  if (!scopePkgId) {
    const staffPkg = allPackages.find((p) => p.code === 'STAFF');
    const permissionIds = staffPkg?.permissions?.map((p) => p.id) ?? [];
    const created = await adminService.createPackage({
      code: scopeCode,
      name: `Phạm vi ĐVCS — ${account.fullName || account.username}`,
      orderIndex: 90,
      description: 'Auto: đơn vị cơ sở user được phép truy cập',
      permissionIds,
      allowedCompanyScopeJson: scopeJson,
    });
    scopePkgId = created.id;
  } else {
    await adminService.updatePackage(scopePkgId, {
      name: existingScopePkg!.name,
      orderIndex: existingScopePkg!.orderIndex,
      isActive: existingScopePkg!.isActive,
      allowedCompanyScopeJson: scopeJson,
    });
  }

  const alreadyAssigned = account.packages.some((p) => p.packageId === scopePkgId);
  if (!alreadyAssigned) {
    await adminService.assignPackage(account.id, { packageId: scopePkgId! });
  }
}

export function resolveAccountAllowedCompanyIds(
  account: BffAccountDetailDto,
  allPackages: BffFeaturePackageDto[],
): string[] {
  const assigned = allPackages.filter((p) =>
    account.packages.some((a) => a.packageId === p.id),
  );
  return mergeAllowedCompanyIdsFromPackages(assigned, account.companyId);
}

export function formatCompanyOptionLabel(c: { id?: string; code?: string; shortName?: string; name: string }): string {
  const key = c.id ?? c.code;
  if (key) return `${key} — ${c.shortName ?? c.name}`;
  return c.shortName ? `${c.shortName} — ${c.name}` : c.name;
}
